"-- Alter orders table to allow bkash, nagad, rocket in payment_method\nALTER TABLE public.orders DROP CONSTRAINT IF EXISTS orders_payment_method_check;\nALTER TABLE public.orders ADD CONSTRAINT orders_payment_method_check CHECK (payment_method = ANY (ARRAY['cod'::text, 'stripe'::text, 'bkash'::text, 'nagad'::text, 'rocket'::text]));\n\n-- Add transaction_id column to orders table if it does not exist\nALTER TABLE public.orders ADD COLUMN IF NOT EXISTS transaction_id text;\n"